import java.util.Scanner;public class GuessingGame2{public static void main(String[] args){int A=(int)Math.round(Math.random()*101);Scanner S=new Scanner(System.in);System.out.print("Welcome to the guessing game! Pick a number between 1-100 (Guess #1): ");String T=S.nextLine();int G= Integer.parseInt(T);int C=1;while(G!=A){C++;if(G < A)System.out.print("Too Low! (Guess #"+C+"): ");else if(G > A)System.out.print("Too High! (Guess #"+C+"): ");T=S.nextLine();G=Integer.parseInt(T);} System.out.println("You got it! You guessed ["+G+"], and the answer was ["+A+"]! Guessed in ["+C+"] Guesses.");}}